% 李萨如曲线生成与可视化% 支持二维和三维曲线，可自定义频率、振幅和相位参数clear; clc; close all;%% 参数设置% North, East, Height的范围North_range = 150; North_bais = 300;East_range = -150; East_bais = 300;Height_range = 20; Height_bais = 50;color = [0.8, 0.3, 0.3];numbers = 100;% 基础参数t = linspace(0, 20, numbers);  % 时间参数dimension = 3;                 % 2=二维曲线，3=三维曲线% 频率比 (决定曲线形状，有理数时闭合，无理数时非闭合)f = [-0.1, -0.1, -0.2] * 10;                 % x, y, z方向频率% 振幅设置% x, y, z方向振幅A = [North_range, East_range, Height_range];                 % 相位偏移 (增加曲线复杂度)phi = [pi/2, 0, pi/2];         % x, y, z方向相位%% 生成李萨如曲线x = A(1) * sin(f(1)*t + phi(1)) + North_bais;y = A(2) * sin(f(2)*t + phi(2)) + East_bais;z = A(3) * t + Height_bais;%% 可视化figure('Position', [100, 100, 800, 600]);ax = axes('Parent', gcf, 'Projection', 'perspective');plot3(x, y, z, 'LineStyle', '--','LineWidth', 1, 'Color', color);hold on;scatter3(x, y, z, 8, t, 'filled', 'MarkerEdgeColor', 'none');colorbar; colormap;axis equal; grid on; box on;xlabel('North (m)', 'FontSize', 12);ylabel('East (m)', 'FontSize', 12);zlabel('Height (m)', 'FontSize', 12);view(3);hold off;%% 保存数据path_ref = [x',y',-z'];% 数据填充% path_ref = [path_ref(1:15,:);...%              (path_ref(15,:) + path_ref(1,:))/2;...%              (path_ref(16,:) + path_ref(1,:))/2;...%              path_ref(16:end,:)];% path_ref = [path_ref(1,:);...%             (path_ref(1,:) * 0.8 + path_ref(2,:) * 0.2);...%             path_ref(2:end-1,:);...%             (path_ref(end-1,:) * 0.8 + path_ref(end,:) * 0.2);...%             path_ref(end,:)];path_ref = [path_ref(1,:);...             (path_ref(1,:) * 0.5 + path_ref(2,:) * 0.5);...             path_ref(2:end-1,:);...             (path_ref(end-1,:) * 0.5 + path_ref(end,:) * 0.5);...             path_ref(end,:)];save('helix_CJA.mat','path_ref');